import React, { useState, useEffect, useRef } from "react";
import { Link, useLocation } from "react-router-dom";

const Navbar = () => {
  const location = useLocation();
  const [isMobileNavVisible, setIsMobileNavVisible] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const headerRef = useRef(null);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  useEffect(() => {
    setIsMobileNavVisible(false);
  }, [location.pathname]);

  const toggleMobileMenu = () => {
    setIsMobileNavVisible(!isMobileNavVisible);
  };

  return (
    <header 
      ref={headerRef} 
      id="header" 
      className={`header glass-effect ${isScrolled ? 'scrolled' : ''} ${isMobileNavVisible ? "header-show" : ""}`}
    >
      <div className="logo">
        <Link to="/" className="text-gradient" style={{ fontWeight: 800, fontSize: '1.5rem', textDecoration: 'none' }}>
          DA.
        </Link>
      </div>

      <i className={`header-toggle bi ${isMobileNavVisible ? "bi-x" : "bi-list"}`} onClick={toggleMobileMenu}></i>

      <nav id="navmenu" className={`navmenu ${isMobileNavVisible ? 'mobile-visible' : ''}`}>
        <ul>
          {location.pathname === "/" ? (
            <>
              <li><a href="#hero" className="active"><i className="bi bi-house"></i><span>Home</span></a></li>
              <li><a href="#about"><i className="bi bi-person"></i><span>About</span></a></li>
              <li><a href="#skills"><i className="bi bi-lightbulb"></i><span>Skills</span></a></li>
              <li><a href="#resume"><i className="bi bi-file-earmark-text"></i><span>Resume</span></a></li>
              <li><a href="#platforms"><i className="bi bi-hdd-stack"></i><span>Platforms</span></a></li>
              <li><a href="#contact"><i className="bi bi-envelope"></i><span>Contact</span></a></li>
            </>
          ) : (
            <li>
              <Link to="/" className="active">
                <i className="bi bi-arrow-left"></i><span>Back Home</span>
              </Link>
            </li>
          )}
        </ul>
      </nav>
    </header>
  );
};

export default Navbar;
